  function peso(n){return '₱'+(Number(n)||0).toLocaleString('en-PH',{minimumFractionDigits:2,maximumFractionDigits:2})}
  function read(k,d){try{var raw=localStorage.getItem(k);return raw?JSON.parse(raw):d}catch(e){return d}}
  function write(k,v){try{localStorage.setItem(k,JSON.stringify(v));return true}catch(e){toast('Storage is full or blocked. Data could not be saved.');return false}}
  function ref(prefix){return prefix+'-'+ymd().replace(/-/g,'')+'-'+Math.random().toString(36).slice(2,7).toUpperCase()}
  function toast(msg){var t=$('oj47Toast'); if(!t){t=document.createElement('div');t.id='oj47Toast';t.className='oj47-toast';document.body.appendChild(t)} t.textContent=msg; t.style.display='block'; clearTimeout(t._timer); t._timer=setTimeout(function(){t.style.display='none'},3200)}
  function audit(action,detail){var arr=read(AUDIT_KEY,[]);arr.unshift({time:iso(),role:role(),action:action,detail:detail||'',staff:localStorage.getItem('oj47_staff')||''});write(AUDIT_KEY,arr.slice(0,700))}
  function getDB(){try{if(typeof DB!=='undefined' && DB && DB.slabs) return DB}catch(e){} return {slabs:{cebu_ormoc:{normal:[20,27.5,32.5],fragile:[35,50,70]},cebu_tagbilaran:{normal:[15,25,30],fragile:[30,45,65]},cebu_getafe:{normal:[10,20,25],fragile:[25,40,60]},cebu_palompon:{normal:[20,27.5,32.5],fragile:[35,50,70]}},freeAllowance:{tourist:10,business:20},paxFares:{cebu_ormoc:{'TC/OA':1430,BC:1950,ST:1144,MI:715},cebu_tagbilaran:{'TC/OA':1000,BC:1560,ST:800,MI:500},cebu_getafe:{'TC/OA':585,BC:1040,ST:468,MI:292.5},cebu_palompon:{'TC/OA':1430,BC:1950,ST:1144,MI:715}},history:[],comps:[],stats:{transactions:0,revenue:0,totalKg:0,routeCounts:{}}} }
  function saveMainDB(){try{if(typeof saveDB==='function') saveDB()}catch(e){}}
  function routeKeys(){var db=getDB(); return Object.keys(db.slabs||{}).sort()}
  function routeLabel(k){try{if(typeof label==='function') return label(k)}catch(e){} var db=getDB(); if(db.schedules && db.schedules[k] && db.schedules[k].title) return db.schedules[k].title; return String(k||'').replace(/_/g,' to ').replace(/\b\w/g,function(c){return c.toUpperCase()})}
  function className(c){return c==='business'?'Business':'Tourist / Open Air'}
  function statusClass(s){s=String(s||'Pending').toLowerCase(); if(s.includes('resolved')) return 'green'; if(s.includes('reject')||s.includes('severe')) return 'pink'; if(s.includes('process')||s.includes('verified')) return 'amber'; return 'gray'}
  function claims(){return read(CLAIM_KEY,[])}
