  function txs(){var a=read(TX_KEY,[]);try{var db=getDB(); if(db.history && db.history.length){var more=db.history.map(function(x){return Object.assign({source:'mainDB'},x)}); a=a.concat(more)}}catch(e){} var seen={}; return a.filter(function(x,i){var id=x.id||x.time||JSON.stringify(x).slice(0,50)+i;if(seen[id])return false; seen[id]=1; return true})}
  function role(){try{return localStorage.getItem(ROLE_KEY)||sessionStorage.getItem(ROLE_KEY)||'pax'}catch(e){return 'pax'}}
  function roleTitle(){var r=role(); return r==='admin'?'Admin':(r==='cashier'?'Cashier':'Passenger')}
  function canStaff(){var r=role(); return r==='cashier'||r==='admin'}
