  function updateClaimReview(){var box=$('oj47ClaimReview'); if(!box)return; var data=claimData(false); box.innerHTML='<b>PSN:</b> '+esc(data.psn||'—')+'<br><b>Passenger:</b> '+esc(data.lastName||'—')+'<br><b>Route:</b> '+esc(routeLabel(data.route))+'<br><b>Baggage:</b> '+esc(data.tag||'—')+' · '+esc(data.baggageType||'—')+' · '+esc(data.color||'—')+'<br><b>Damage:</b> '+esc(data.damageType)+' · '+esc(data.severity)+'<br><b>Timeline:</b><div class="oj47-timeline">'+timelineHTML('Pending')+'</div>'}
  function claimData(require){var data={psn:clean($('oj47Psn')&&$('oj47Psn').value),lastName:clean($('oj47LastName')&&$('oj47LastName').value),route:$('oj47ClaimRoute')&&$('oj47ClaimRoute').value,tripDate:$('oj47TripDate')&&$('oj47TripDate').value,vessel:clean($('oj47Vessel')&&$('oj47Vessel').value),tag:clean($('oj47BaggageTag')&&$('oj47BaggageTag').value),baggageType:clean($('oj47BaggageType')&&$('oj47BaggageType').value),color:clean($('oj47ClaimColor')&&$('oj47ClaimColor').value),severity:$('oj47ClaimSeverity')&&$('oj47ClaimSeverity').value||'Minor',damageType:$('oj47ClaimDamage')&&$('oj47ClaimDamage').value||'Scratch / Dent',notes:clean($('oj47ClaimNotes')&&$('oj47ClaimNotes').value),photo:window.__oj47ClaimPhoto||'',evidenceId:window.__oj47ClaimEvidenceId||''}; if(require && (!data.psn||!data.lastName||!data.route||!data.damageType)){toast('Please enter PSN, last name, route, and damage details.');return null} return data}
