  window.oj47UseLastEvidence=function(){var ev=evidence()[0]; if(!ev){toast('No saved scanner evidence yet. Open Damage Scanner first.');return} window.__oj47ClaimEvidenceId=ev.id; window.__oj47ClaimPhoto=ev.photo||''; if($('oj47BaggageTag')&&!$('oj47BaggageTag').value)$('oj47BaggageTag').value=ev.claimRef||ev.tag||ev.id; if($('oj47BaggageType'))$('oj47BaggageType').value=ev.baggageType||''; if($('oj47ClaimColor'))$('oj47ClaimColor').value=ev.color||''; if($('oj47ClaimSeverity'))$('oj47ClaimSeverity').value=ev.severity||'Minor'; if($('oj47ClaimDamage'))$('oj47ClaimDamage').value=ev.damageType||'Scratch / Dent'; if($('oj47ClaimPhotoBox')&&ev.photo)$('oj47ClaimPhotoBox').innerHTML='<img class="oj47-preview" src="'+ev.photo+'" alt="Scanner evidence">'; updateClaimReview(); toast('Scanner evidence added to claim.')};
