  function renderScanner(){lastScanner=null; $('oj47Page').innerHTML='<div class="oj47-view"><div class="oj47-hero"><div class="oj47-title-row"><div><h2>Smart AR Damage Scanner</h2><div class="oj47-sub">Reviewed scanner: fields stay blank until a real camera frame or uploaded image is analyzed. No default PALOMPON / Unknown autofill. Route is filled only when a readable barcode/QR or visible text route is detected.</div></div><span class="oj47-chip pink">Image-Based Autofill</span></div></div><div class="oj47-grid2"><div class="oj47-card glow"><h3>Camera / Upload Evidence</h3><div class="oj47-camera"><video id="oj47Video" autoplay playsinline muted></video><canvas id="oj47Canvas" class="oj47-hidden"></canvas><img id="oj47Preview" class="oj47-hidden" alt="Evidence preview"><div class="oj47-reticle"></div></div><div id="oj47ScanStatus" class="oj47-note">Waiting for actual image. Press Start Camera, Auto Capture, Capture Now, or Upload Image.</div><div class="oj47-meter"><span id="oj47QualityBar"></span></div><div class="oj47-grid4" style="margin-top:10px"><div class="oj47-kpi cyan"><b id="oj47Quality">0%</b><span>Evidence Score</span></div><div class="oj47-kpi"><b id="oj47Sharpness">0</b><span>Sharpness</span></div><div class="oj47-kpi"><b id="oj47Light">0</b><span>Light</span></div><div class="oj47-kpi"><b id="oj47Pixels">0</b><span>Pixels</span></div></div><div class="oj47-actions" style="margin-top:10px"><button class="primary" onclick="oj47StartCamera()">Start Camera</button><button class="accent" onclick="oj47StartAutoCapture()">Start Auto Capture</button><button onclick="oj47CaptureFrame()">Capture Now</button><button class="danger" onclick="oj47StopCamera()">Stop</button><button onclick="oj47Retake()">Retake / Clear</button><label class="oj47-upload accent">Upload Image<input hidden type="file" accept="image/*" onchange="oj47UploadImage(event)"></label></div></div><div class="oj47-card glow"><h3>Auto-Filled From Image</h3><div class="oj47-form"><div class="oj47-grid2"><div class="oj47-field"><label>Claim / Tag</label><input id="oj47ScanTag" placeholder="Barcode/QR or image hash"></div><div class="oj47-field"><label>Destination / Route</label><input id="oj47ScanDestination" placeholder="Blank unless detected"></div></div><div class="oj47-grid2"><div class="oj47-field"><label>Barcode / QR</label><input id="oj47ScanBarcode" placeholder="Not detected yet"></div><div class="oj47-field"><label>Color</label><input id="oj47ScanColor" placeholder="Waiting for image"></div></div><div class="oj47-grid2"><div class="oj47-field"><label>Size</label><input id="oj47ScanSize" placeholder="Waiting for image"></div><div class="oj47-field"><label>Baggage Type</label><input id="oj47ScanType" placeholder="Waiting for image"></div></div><div class="oj47-grid2"><div class="oj47-field"><label>Damage Hint</label><input id="oj47ScanDamage" placeholder="Waiting for image"></div><div class="oj47-field"><label>Severity</label><select id="oj47ScanSeverity"><option>Minor</option><option>Moderate</option><option>Severe</option></select></div></div><div class="oj47-field"><label>Staff / Shift</label><input id="oj47ScanStaff" value="'+esc(localStorage.getItem('oj47_staff')||'Dock Staff')+'"></div><div class="oj47-field"><label>Manual Notes</label><textarea id="oj47ScanNotes" placeholder="Optional manual notes"></textarea></div><div class="oj47-actions"><button class="primary" onclick="oj47SaveEvidence()">Save Evidence</button><button onclick="oj47PDFEvidence()">Evidence PDF</button></div></div><div id="oj47RecentEvidence" style="margin-top:13px"></div></div></div></div>'; renderRecentEvidence()}
  function scanStatus(msg,cls){var el=$('oj47ScanStatus'); if(el){el.className='oj47-note '+(cls||'');el.innerHTML=msg}}
  function setQuality(n){n=Math.max(0,Math.min(100,Math.round(n||0))); if($('oj47Quality'))$('oj47Quality').textContent=n+'%'; if($('oj47QualityBar'))$('oj47QualityBar').style.width=n+'%'}
  window.oj47StartCamera=function(){var video=$('oj47Video'); if(!video||!navigator.mediaDevices||!navigator.mediaDevices.getUserMedia){scanStatus('Camera API is not available. Use Upload Image fallback.','warn');return} navigator.mediaDevices.getUserMedia({video:{facingMode:{ideal:'environment'},width:{ideal:1280},height:{ideal:720}},audio:false}).then(function(stream){scannerStream=stream;video.srcObject=stream;video.play().catch(function(){});scanStatus('Camera ready. Aim at claim stub/tag and baggage, then tap Capture Now or Start Auto Capture.','');toast('Camera started.')}).catch(function(err){scanStatus('Camera blocked or unavailable: '+esc(err.message)+'. Use Upload Image or manual fields.','bad')})};
  window.oj47StopCamera=function(){if(scannerTimer){clearInterval(scannerTimer);scannerTimer=null} if(scannerStream){scannerStream.getTracks().forEach(function(t){t.stop()});scannerStream=null} var v=$('oj47Video'); if(v)v.srcObject=null; scanStatus('Camera stopped. Upload image fallback remains available.','warn')};
  window.oj47StartAutoCapture=function(){if(scannerTimer){clearInterval(scannerTimer);scannerTimer=null;scanStatus('Auto capture stopped.','warn');return} if(!$('oj47Video')||!$('oj47Video').srcObject){oj47StartCamera();scanStatus('Camera is starting. After permission is granted, tap Start Auto Capture again. Upload Image is available if camera is blocked.','warn'); return} scanStatus('Auto capture running. Hold steady; image analysis will update fields when a real frame is available.',''); scannerTimer=setInterval(function(){try{oj47CaptureFrame(true)}catch(e){}},1700)};
  window.oj47CaptureFrame=function(auto){var v=$('oj47Video'), c=$('oj47Canvas'); if(!v||!c||!v.videoWidth){if(!auto)scanStatus('No live camera frame yet. Start camera or upload an image.','warn'); return} c.width=Math.min(1200,v.videoWidth); c.height=Math.round(c.width*(v.videoHeight/v.videoWidth)); c.getContext('2d').drawImage(v,0,0,c.width,c.height); analyzeCanvas(c,auto?'auto camera':'camera')};
  window.oj47UploadImage=function(ev){var f=ev.target.files&&ev.target.files[0]; if(!f)return; imageFileToData(f,1200,.76,function(src){var img=new Image(); img.onload=function(){var c=drawImage(img,1200); analyzeCanvas(c,'upload')}; img.onerror=function(){scanStatus('Could not read uploaded image. Try another photo.','bad')}; img.src=src})};
  window.oj47Retake=function(){lastScanner=null; ['oj47ScanTag','oj47ScanDestination','oj47ScanBarcode','oj47ScanColor','oj47ScanSize','oj47ScanType','oj47ScanDamage','oj47ScanNotes'].forEach(function(id){var el=$(id); if(el)el.value=''}); setQuality(0); if($('oj47Sharpness'))$('oj47Sharpness').textContent='0'; if($('oj47Light'))$('oj47Light').textContent='0'; if($('oj47Pixels'))$('oj47Pixels').textContent='0'; var img=$('oj47Preview'); if(img){img.classList.add('oj47-hidden');img.removeAttribute('src')} scanStatus('Cleared. Capture or upload a real image to auto-fill fields.','warn')};
