  function analyzePixels(canvas){var ctx=canvas.getContext('2d',{willReadFrequently:true}), w=canvas.width,h=canvas.height, img=ctx.getImageData(0,0,w,h).data; var step=Math.max(4,Math.floor(Math.sqrt(w*h)/120)); var r=0,g=0,b=0,n=0, light=0, sat=0, edge=0, dark=0, bright=0, cx1=Math.floor(w*.18), cx2=Math.floor(w*.82), cy1=Math.floor(h*.18), cy2=Math.floor(h*.82); for(var y=cy1;y<cy2;y+=step){for(var x=cx1;x<cx2;x+=step){var i=(y*w+x)*4, rr=img[i],gg=img[i+1],bb=img[i+2]; r+=rr;g+=gg;b+=bb;n++; var max=Math.max(rr,gg,bb), min=Math.min(rr,gg,bb), lum=(rr*0.299+gg*0.587+bb*0.114); light+=lum; sat+=max-min; if(lum<72)dark++; if(lum>210)bright++; var j=(Math.min(h-1,y+step)*w+Math.min(w-1,x+step))*4; edge+=Math.abs(lum-(img[j]*0.299+img[j+1]*0.587+img[j+2]*0.114));}}
    r/=n||1;g/=n||1;b/=n||1;light/=n||1;sat/=n||1;edge/=n||1; var cover=(dark+bright)/(n||1)*100; var pixels=Math.round((w*h)/1000); return {w:w,h:h,pixels:pixels,r:r,g:g,b:b,light:light,sat:sat,edge:edge,cover:cover,color:classifyColor(r,g,b,sat,light),hash:imageHash(r,g,b,edge,light,w,h)} }
  function classifyColor(r,g,b,sat,light){if(light<45)return 'Black'; if(light>224&&sat<35)return 'White'; if(sat<22)return light>165?'Silver':'Gray'; if(r>g*1.22&&r>b*1.22)return r>180&&b>105?'Pink':'Red'; if(b>r*1.16&&b>g*1.08)return 'Blue'; if(g>r*1.08&&g>b*1.08)return 'Green'; if(r>135&&g>85&&b<85)return 'Brown'; if(r>168&&g>138&&b<92)return 'Yellow'; if(r>180&&g>96&&b<90)return 'Orange'; if(r>105&&b>118&&g<120)return 'Purple'; return nearestColor(r,g,b)}
