  function classifyBag(m){var aspect=m.w/m.h; var type='Suitcase'; if(aspect>1.55) type='Duffel bag / long item'; else if(aspect<.72) type='Upright suitcase / trolley'; else if(m.edge>26&&/Brown|White|Gray|Silver/.test(m.color)) type='Box / carton'; else if(m.edge>30) type='Soft fabric luggage'; else if(/Black|Blue|Red|Pink|Purple|Silver/.test(m.color)) type='Hard-shell suitcase'; var size=m.cover>55||m.pixels>750?'Large':(m.cover>30||m.pixels>360?'Medium':'Small'); var damage='Needs manual review'; if(m.edge>38&&m.sat>45) damage='Possible scratch / dent / torn area'; else if(m.light<76&&m.sat<38) damage='Possible wet / dark stain area'; else if(m.edge>28) damage='Visible scuff / texture irregularity'; else damage='No strong damage pattern detected'; var severity=m.edge>42||m.light<55?'Severe':(m.edge>28||m.sat>70?'Moderate':'Minor'); var quality=Math.round(Math.max(18,Math.min(98,(m.light>60&&m.light<220?25:12)+(m.edge>14?22:10)+(m.pixels>500?22:12)+(m.cover>20?17:10)+(m.sat>18?12:6)))); return {size:size,type:type,damage:damage,severity:severity,quality:quality}}
