  function routeFromCode(code){var s=String(code||'').toUpperCase(); for(var i=0;i<KNOWN_ROUTES.length;i++){if(s.indexOf(KNOWN_ROUTES[i])>=0)return KNOWN_ROUTES[i]} return ''}
  function applyScanner(m,photo,source,barcode){var c=classifyBag(m), dest=routeFromCode(barcode); lastScanner={id:ref('OJ-DMG'),createdAt:iso(),source:source,photo:photo,tag:m.hash,claimRef:m.hash,barcode:barcode||'',destination:dest,color:m.color,size:c.size,baggageType:c.type,damageType:c.damage,severity:c.severity,quality:c.quality,light:Math.round(m.light),sharpness:Math.round(m.edge),pixels:m.pixels,autoSummary:'Image analyzed from '+source+': '+m.color+' '+c.size+' '+c.type+'. '+c.damage+'. Score '+c.quality+'%.'}; if($('oj47Preview')){$('oj47Preview').src=photo;$('oj47Preview').classList.remove('oj47-hidden')} var set=function(id,val){var el=$(id);if(el)el.value=val||''}; set('oj47ScanTag',barcode||m.hash); set('oj47ScanDestination',dest); set('oj47ScanBarcode',barcode); set('oj47ScanColor',m.color); set('oj47ScanSize',c.size); set('oj47ScanType',c.type); set('oj47ScanDamage',c.damage); if($('oj47ScanSeverity'))$('oj47ScanSeverity').value=c.severity; setQuality(c.quality); if($('oj47Sharpness'))$('oj47Sharpness').textContent=Math.round(m.edge); if($('oj47Light'))$('oj47Light').textContent=Math.round(m.light); if($('oj47Pixels'))$('oj47Pixels').textContent=m.pixels+'k'; scanStatus('Image analyzed. Fields were filled from the actual '+esc(source)+' image. '+(dest?'Route detected from code: '+esc(dest):'No readable route code detected; destination is intentionally left blank for manual entry.'),''); audit('Scanner image analyzed',lastScanner.id)}
  window.oj47SaveEvidence=function(){if(!lastScanner){toast('Capture or upload an actual image first.');return} var ev=Object.assign({},lastScanner,{claimRef:clean($('oj47ScanTag')&&$('oj47ScanTag').value)||lastScanner.claimRef,destination:clean($('oj47ScanDestination')&&$('oj47ScanDestination').value)||'',barcode:clean($('oj47ScanBarcode')&&$('oj47ScanBarcode').value)||'',color:clean($('oj47ScanColor')&&$('oj47ScanColor').value)||lastScanner.color,size:clean($('oj47ScanSize')&&$('oj47ScanSize').value)||lastScanner.size,baggageType:clean($('oj47ScanType')&&$('oj47ScanType').value)||lastScanner.baggageType,damageType:clean($('oj47ScanDamage')&&$('oj47ScanDamage').value)||lastScanner.damageType,severity:clean($('oj47ScanSeverity')&&$('oj47ScanSeverity').value)||lastScanner.severity,staff:clean($('oj47ScanStaff')&&$('oj47ScanStaff').value)||'Dock Staff',notes:clean($('oj47ScanNotes')&&$('oj47ScanNotes').value)||''}); localStorage.setItem('oj47_staff',ev.staff); var arr=evidence(); arr.unshift(ev); write(EVIDENCE_KEY,arr.slice(0,400)); try{var v11=read('oj_damage_master_v11_backup',{nextCaseSeq:1,cases:[],settings:{}}); v11.cases=v11.cases||[]; v11.cases.unshift({caseId:ev.id,destination:ev.destination,tagNo:ev.claimRef,color:ev.color,size:ev.size,baggageType:ev.baggageType,damageType:ev.damageType,severity:ev.severity,status:'New',phtTimestamp:ev.createdAt,evidenceScore:ev.quality,summary:ev.autoSummary,notes:ev.notes,photos:[{photoId:ref('P'),role:'V47 Smart Evidence',dataUrl:ev.photo,quality:ev.quality,createdAt:ev.createdAt}]}); write('oj_damage_master_v11_backup',v11)}catch(e){} audit('Evidence saved',ev.id); toast('Evidence saved: '+ev.id); renderRecentEvidence()};
